def _parse_moose_version():
    """Read version and release codename from moose-core CHANGELOG.md."""
    import re
    if not _moose_core:
        return None, None
    changelog = os.path.join(_moose_core, 'CHANGELOG.md')
    if not os.path.exists(changelog):
        return None, None
    with open(changelog) as f:
        lines = f.readlines()
    for i, line in enumerate(lines):
        m = re.match(r'##\s+\[(\d+\.\d+[\.\d]*)\]', line)
        if m:
            ver = m.group(1)
            codename = None
            for next_line in lines[i+1:]:
                stripped = next_line.strip()
                if stripped and not stripped.startswith('#'):
                    codename = stripped
                    break
            return ver, codename
    return None, None


def _write_latest_release():
    """Extract latest release section from CHANGELOG.md and write as RST."""
    import re
    if not _moose_core:
        return
    changelog = os.path.join(_moose_core, 'CHANGELOG.md')
    if not os.path.exists(changelog):
        return
    with open(changelog) as f:
        lines = f.readlines()

    # Find first versioned release
    start = None
    ver = ''
    date = ''
    for i, line in enumerate(lines):
        m = re.match(r'##\s+\[(\d+\.\d+[\.\d]*)\]\s*-?\s*(.*)', line)
        if m:
            start = i
            ver = m.group(1)
            date = m.group(2).strip()
            break

    if start is None:
        return

    # Collect lines until the next ## release entry
    section = []
    for line in lines[start + 1:]:
        if re.match(r'##\s+\[', line):
            break
        section.append(line)

    # GitHub release link
    gh_url = f'https://github.com/MooseNeuro/moose-core/releases/tag/v{ver}'
    gh_link = f'\n> **[View release v{ver} on GitHub]({gh_url})**\n\n'

    # Build MD output
    out_path = os.path.join(os.path.dirname(__file__), '_latest_release.md')
    with open(out_path, 'w') as f:
        f.write(f'## {ver}' + (f' — {date}' if date else '') + '\n')
        f.write(gh_link)
        f.write(''.join(section))

_write_latest_release()

