import re

def _plain_to_math(text):
    """Convert a plain-text ODE/equation string to minimal LaTeX."""
    t = text.strip()
    t = re.sub(r'\bd\s*(\w+)\s*/\s*d(\w+)\b', r'\\frac{d\1}{d\2}', t)
    t = re.sub(r'\^(\w+)', r'^{\1}', t)
    t = re.sub(r'\b([A-Z])m\b', r'\1_m', t)
    t = re.sub(r'\btau_(\w+)\b', r'\\tau_{\1}', t)
    t = re.sub(r'\btau\b', r'\\tau', t)
    t = re.sub(r'\bexp\b', r'\\exp', t)
    t = re.sub(r'\bsqrt\b', r'\\sqrt', t)
    t = re.sub(r'\*', r' ', t)
    return t

def _is_equation(line):
    """Return True if line looks like a plain-text differential/algebraic equation."""
    s = line.strip()
    if not s or s.startswith('#') or s.startswith('..'):
        return False  # RST directives already handled
    # Find first standalone = (not <=, >=, !=, ==)
    eq_match = re.search(r'(?<![<>!=])=(?!=)', s)
    if not eq_match:
        return False
    # If the LHS contains a comma, it's prose not math
    lhs = s[:eq_match.start()]
    if ',' in lhs:
        return False
    # Allow spaces between d and variable: d Vm /dt, d u / dt, dVm/dt
    has_deriv = bool(re.search(r'd\s*\w+\s*/\s*d\w+', s))
    has_math  = bool(re.search(r'\b\w+[\*/^]\w+', s))  # tight ops only (avoids RST *italic*)
    # Exclude Python-style assignments (lines with word = word without spaces around ops)
    is_code   = bool(re.match(r'^\w+\s*=\s*\w', s) and '*' not in s and '/' not in s)
    return (has_deriv or has_math) and not is_code

def _fix_docstring(app, what, name, obj, options, lines):
    """Post-process docstrings to improve RST rendering without editing upstream source."""
    new_lines = []
    i = 0
    in_literal = False   # inside a :: literal block — skip all transforms
    lit_base = 0         # indent level of the :: line
    after_colons = False # waiting for content after a :: line

    while i < len(lines):
        line = lines[i]
        stripped = line.strip()
        indent = len(line) - len(line.lstrip()) if stripped else None

        # --- Literal-block state machine ---
        if after_colons:
            if stripped == '':
                new_lines.append(line)
                i += 1
                continue
            after_colons = False
            if indent is not None and indent > lit_base:
                in_literal = True  # entering literal block; fall through to in_literal check

        if in_literal:
            if stripped == '':
                new_lines.append(line)
                i += 1
                continue
            if indent is not None and indent <= lit_base:
                in_literal = False  # dedented — exit block, fall through to normal processing
            else:
                new_lines.append(line)  # inside block, pass through unchanged
                i += 1
                continue

        # --- Normal RST processing (not in a literal block) ---

        # Wrap bare path-like strings in backticks for inline code
        line = re.sub(
            r'(?<![`\w])(/[\w{}/._-]+(?:/[\w{}/._-]+)+)',
            r'``\1``',
            line
        )

        # Convert bare "References:" paragraph into a rubric
        if line.strip() == 'References:':
            new_lines.append('.. rubric:: References')
            i += 1
            continue

        # Detect start of a literal block (line ending with ::)
        if stripped and line.rstrip().endswith('::'):
            lit_base = indent if indent is not None else 0
            after_colons = True
            new_lines.append(line)
            i += 1
            continue

        # Convert plain-text equation lines to .. math:: blocks
        if _is_equation(line):
            eq_indent = len(line) - len(line.lstrip())
            pad = ' ' * eq_indent
            latex = _plain_to_math(line)
            new_lines.append('')
            new_lines.append(pad + '.. math::')
            new_lines.append('')
            new_lines.append(pad + '   ' + latex)
            new_lines.append('')
            i += 1
            continue

        new_lines.append(line)
        i += 1

    lines[:] = new_lines

def _fix_source_rst(app, docname, source):
    """Transform RST source before parsing — fixes hardcoded plain text in classes_demos."""
    if 'classes_demos' not in docname:
        return
    text = source[0]

    # 1. Remove bare function.name()[source] lines (automodule already renders these as dt.sig)
    text = re.sub(r'^\w+\.[\w.]+\([^)]*\)\[source\]\s*\n', '', text, flags=re.MULTILINE)

    # 2. Remove duplicate heading that follows automodule + :members:
    text = re.sub(
        r'(\.\. automodule::.*\n\s+:members:.*\n\n+)[^\n]+\n\n',
        r'\1',
        text
    )

    # 3. Wrap moose.connect() calls and formula lines into code blocks
    lines = text.split('\n')
    result = []
    code_buf = []

    def flush_code():
        if code_buf:
            result.append('')
            result.append('.. code-block:: python')
            result.append('')
            result.extend('   ' + l for l in code_buf)
            result.append('')
            code_buf.clear()

    for line in lines:
        if re.match(r'^(moose\.connect\(|f\([a-zA-Z0-9]|[a-zA-Z] ?= .+[\*\+])', line):
            code_buf.append(line)
        else:
            flush_code()
            result.append(line)
    flush_code()

    source[0] = '\n'.join(result)

def _skip_external_members(app, what, name, obj, skip, options):
    """Skip members that were imported from external packages (e.g. via 'from pylab import *').
    Only keeps members whose __module__ belongs to the documented module."""
    import inspect
    if skip:
        return True
    if what in ('function', 'class', 'exception', 'method'):
        obj_module = getattr(obj, '__module__', None)
        top_module = name.split('.')[0]
        if obj_module is None:
            # C-extension builtins (numpy random functions etc.) — always external
            if inspect.isbuiltin(obj):
                return True
        elif not obj_module.startswith(top_module):
            return True
    return skip

def setup(app):
    app.connect('autodoc-process-docstring', _fix_docstring)
    app.connect('source-read', _fix_source_rst)
    app.connect('autodoc-skip-member', _skip_external_members)
